/*!40000 ALTER TABLE `relevant_experience` DISABLE KEYS */;
INSERT INTO `relevant_experience` VALUES (1,1,'Desde 1988 inicié mi experiencia en actividades de inspección de cargamentos de comercio exterior para determinación de cantidades e inventarios, de productos tales como Hidrocarburos; Agrícolas, minerales, determinacion de peso mediante draft survey, muestreo de granos, minerales y fertilizantes, consolidación de contenedores. Con base a las normas técnicas marinas del API MPMS, reglas GAFTA, principalmente.',1,'2026-06-16 17:38:11'),(2,1,'Coordinación de actividades diarias de los inspectores técnicos, así como la revisión de reportes generados por los inspectores en campo y el posterior envío de la información a nuestros clientes de los trabajos realizados, generación y cierre de expedientes, control de insumos y equipos de PP, administrar recursos y control de Caja Chica.',2,'2026-06-16 17:38:11'),(3,1,'A partir de marzo de 2015 reconocido para realizar actividades de inspección en el alcance acreditado por la ema con base a la norma ISO/IEC 17020:2012 para la materia Producto y desde 2019 como \"muestrero\" de GLP y destilados con base a la norma ISO /IEC 17025.',3,'2026-06-16 17:38:11'),(4,1,'A partir de 2021 reconocido para realizar actividades de inspección en el alcance acreditado por la ema con base a la norma ISO/IEC 17020:2012 para la materia de reglas de muestreo y pesaje GAFTA, incluyendo método interno para determinación de cantidad mediante Draft Survey.',4,'2026-06-16 17:38:11'),(5,5,'Experiencia de 11 años como Inspector técnico en operaciones de carga seca, contenedores, bodegas, almacenadoras, inventarios de azúcar, granos, semillas, aceites, combustibles y líquidos diversos, verificación de calidad y cantidad de productos derivados del petróleo e inventarios mensuales',1,'2026-06-16 17:38:11'),(6,7,'En 1997 inicié mi experiencia en actividades de inspección de cargamentos de comercio exterior para determinación de cantidades e inventarios, de productos tales como Hidrocarburos; Agrícolas, minerales, determinacion de peso mediante draft survey, muestreo de granos, minerales y fertilizantes, consolidación de contenedores. Con base a las normas técnicas marinas del API MPMS principalmente.',1,'2026-06-16 17:38:11'),(7,7,'Desde 2013 Inspector Técnico acreditado ISO/IEC 17020 en el alcance de Producto y como \"muestrero\" de GLP.',2,'2026-06-16 17:38:11'),(8,7,'Signatario acreditado por la ema para la norma ISO/IEC 17025:2017, con alcance en métodos de ensayo para análisis de gas licuado de petróleo.',3,'2026-06-16 17:38:11'),(9,8,'05 años en el área de inspección a nivel operativo, calidad y supervisión de las actividades de inspección con base normas técnicas tales como API, ASTM, NMX, entre otras; principalmente en el área de productos agrícolas, hidrocarburos, petrolíferos, aceites de origen animal y vegetal, químicos y sus derivados.',1,'2026-06-16 17:38:11'),(10,8,'Asimismo, realizando inspecciones técnicas para todo tipo de cargas e inspección de contenedores, entre otras, basadas en especificaciones del cliente y el cumplimiento de las normas y estándares internacionales.',2,'2026-06-16 17:38:11'),(11,9,'Desde 2006 inició mi experiencia en inspección, muestreo, análisis y pruebas de laboratorio para gas LP con base en normas tales como API, ASTM, NOM, NMX, entre otras. Así como atestiguamiento de análisis a diversos hidrocarburos, basados en especificaciones del cliente y el cumplimiento de las normas y estándares internacionales.',1,'2026-06-16 17:38:11'),(12,9,'Experiencia en área administrativa como elaboración de reportes, ordenes de trabajo, expedientes del cliente, control de calidad y llenado de formatos. Signataria acreditada por la EMA, en el alcance de métodos de ensayo para análisis de gas licuado de petróleo en laboratorios de OTI México.',2,'2026-06-16 17:38:11'),(13,10,'Líder en inspección y control de calidad en hidrocarburos, especializado en gestión operativa y desarrollo de centros operativos. Experto en logística integral enfocado a la eficiencia, capacitación técnica, mentoría y formación de equipos, análisis de rentabilidad y expansión de mercado.',1,'2026-06-16 17:38:11'),(14,10,'Coordinación de inspecciones de carga/descarga en buques, plantas y autotanques, asegurando calidad y cumplimiento normativo en productos líquidos. Supervisión de personal, así como generación de informes técnicos y enlace con la Gerencia General y clientes para cotizaciones y acompañamiento durante los servicios.',2,'2026-06-16 17:38:11'),(15,10,'Desde 2004 inicié mi experiencia en la industria química, desempeñando actividades en áreas operativas que incluyen laboratorios de análisis, departamentos de inspección y servicios técnicos enfocados a la industria.',3,'2026-06-16 17:38:11'),(16,10,'Reconocido para realizar actividades de inspección en el alcance acreditado por la ema con base a la norma ISO/IEC 17020: 2012, desde 2013.',4,'2026-06-16 17:38:11'),(17,10,'Reconocido para realizar actividades de inspección en el alcance acreditado por la ema con base a la norma ISO/IEC 17025: 2017 desde 2018, con alcance en métodos de ensayo para análisis de gas licuado de petróleo y destilados de petróleo.',5,'2026-06-16 17:38:11'),(18,11,'En 2011 inicié mi experiencia en actividades de inspección de cargamentos de comercio exterior para determinación de cantidades e inventarios, de productos tales como Hidrocarburos; Agrícolas, minerales, determinacion de peso mediante draft survey, muestreo de granos, minerales y fertilizantes, consolidación de contenedores. Con base a las normas técnicas marinas del API MPMS, reglas GAFTA, principalmente.',1,'2026-06-16 17:38:11'),(19,11,'Desde 2020 Inspector Técnico acreditado ISO/IEC 17020 en el alcance de Producto y como \"muestrero\" de GLP con base a la norma ISO /IEC 17025.',2,'2026-06-16 17:38:12'),(20,13,'En 2011 inició mi experiencia profesional relacionada con muestreo, análisis y pruebas de laboratorio para gas LP con base en normas tales como ASTM, NOM, NMX, entre otras. Así como atestiguamiento de análisis a diversos hidrocarburos, basados en especificaciones del cliente y el cumplimiento de las normas y estándares internacionales.',1,'2026-06-16 17:38:12'),(21,13,'Signatario acreditado por la ema para la norma ISO/IEC 17025:2017, con alcance en métodos de ensayo para análisis de gas licuado de petróleo.',2,'2026-06-16 17:38:12'),(22,14,'Inspeccion de rollos de bobina, varilla, rollos de alambron, vigas, placas de acero, tubos, carga proyecto y atados de madera. Inspeccion y consolidacion de carga en general. Realizar inventarios de granos y semillas. Inspeccion y consolidacion de carga(granos a granel) en barcos graneleros. Realizar y ejecutar proyectos de inspeccion en el area agricola, relacionados con calidad, cantidad de granos y semillas. Inspeccion, muestreo y analisis de calidad fisica, fisiologica y sanitaria (determinacion de micotoxinas) granos y semillas.',1,'2026-06-16 17:38:12'),(23,16,'Experiencia profesional de 19 años en actividades de inspección, como servicios de inspección de diversos productos agrícolas, inentarios, derivados del petroleo e inspecciones técnicas tales como Consolidación de Contenedores e Inspecciones de Cantidades y Calidad, entre otras, basados en especificaciones del cliente o partes involucradas y el cumplimiento de acuerdo a estándares internacionales como ISO 9000, principalmente.',1,'2026-06-16 17:38:12'),(24,17,'Desde 2012 inicié actividades en el sector de la Inspecciones del Petróleo y sus derivados, realizando cálculos a bordo de buque tanques en las terminales diversas de Petróleos Mexicanos, así como atestiguamiento de análisis en laboratorio y a partir del año 2019 se me asigna como Supervisor de Operaciones en la oficina de Coatzacoalcos.',1,'2026-06-16 17:38:12'),(25,17,'Coordinación de actividades diarias de los inspectores técnicos, así como la revisión de reportes generados por los inspectores en campo y el posterior envío de la información a nuestros clientes de los trabajos realizados a PMI de Hidrocarburos, generación y cierre de expedientes, elaboración en conjunto con el Gerente de Operaciones de reportes trimestrales, control de inventarios, equipos de medición, programa de calibración de equipos de medición, insumos y equipos de PP, administrar recursos y control de Caja Chica.',2,'2026-06-16 17:38:12'),(26,17,'Participación como Auditor Interno en el área de operaciones de acuerdo con el programa de auditorías internas que se programan anualmente.',3,'2026-06-16 17:38:12'),(27,17,'Reconocido para realizar actividades de inspección en el alcance acreditado por la ema con base a la norma ISO/IEC 17020: 2012, desde 2015.',4,'2026-06-16 17:38:12'),(28,18,'Actualmente me desarrollo como Inspector Técnico encargado de la verificación de las condiciones de almacenamiento, condiciones de calidad y cantidad de productos perecederos y no perecederos en cargas secas o refrigeradas, de las condiciones de empaque, embalaje y el cumplimiento de algunas normas requeridas por el embalaje. Del atestiguamiento en la toma de muestras para laboratorio, cuarteo y distribución para laboratorio y retención. Experiencia de aproximadamente de 11 años. Además como personal de apoyo para la verificación de la carga a buque de productos agroquímicos.',1,'2026-06-16 17:38:12'),(29,20,'En 2013 inicié mi experiencia en actividades de inspección de cargamentos de comercio exterior para determinación de cantidades e inventarios, de productos tales como Hidrocarburos; Agrícolas, minerales, determinacion de peso mediante draft survey, muestreo de granos, minerales y fertilizantes, consolidación de contenedores. Con base a las normas técnicas marinas del API MPMS, reglas GAFTA, principalmente.',1,'2026-06-16 17:38:12'),(30,20,'Desde 2020 Inspector Técnico acreditado ISO/IEC 17020 en el alcance de Producto y como \"muestrero\" de GLP con base a la norma ISO /IEC 17025. Desde 2021 Inspector Técnico acreditado ISO/IEC 17020 en el alcance de las reglas GAFTA (inspección y muestreo).',2,'2026-06-16 17:38:12'),(31,20,'Signatario acreditado por la ema para la norma ISO/IEC 17025:2017, con alcance en métodos de ensayo para análisis de gas licuado de petróleo.',3,'2026-06-16 17:38:12'),(32,21,'Experiemcia de 16 años como Inspector técnico en operaciones de carga seca, contenedores, bodegas, almacenadoras, inventarios de azúcar, granos, semillas, aceites, combustibles y líquidos diversos, verificación de calidad y cantidad de productos derivados del petróleo e inventarios mensuales',1,'2026-06-16 17:38:12'),(33,22,'En 1996 inicié mi experiencia en actividades de inspección de cargamentos de comercio exterior para determinación de cantidades e inventarios, de productos tales como Hidrocarburos; Agrícolas, minerales, determinacion de peso mediante draft survey, muestreo de granos, minerales y fertilizantes, consolidación de contenedores. Con base a las normas técnicas marinas del API MPMS, reglas GAFTA, principalmente.',1,'2026-06-16 17:38:12'),(34,22,'Desde 2020 Inspector Técnico acreditado ISO/IEC 17020 en el alcance de Producto y como \"muestrero\" de GLP con base a la norma ISO /IEC 17025. Desde 2021 Inspector Técnico acreditado ISO/IEC 17020 en el alcance de las reglas GAFTA (inspección y muestreo).',2,'2026-06-16 17:38:12'),(35,24,'En 1991 inicié mi experiencia en actividades de inspección de cargamentos de comercio exterior para determinación de cantidades e inventarios, de productos tales como Hidrocarburos; Agrícolas, minerales, determinacion de peso mediante draft survey, muestreo de granos, minerales y fertilizantes, consolidación de contenedores. Con base a las normas técnicas marinas del API MPMS, reglas GAFTA, principalmente.',1,'2026-06-16 17:38:12'),(36,24,'Desde 2015 Inspector Técnico acreditado ISO/IEC 17020 en el alcance de Producto.',2,'2026-06-16 17:38:12'),(37,25,'Desde 2015 inició mi experiencia en inspección, muestreo, análisis y pruebas de laboratorio para gas LP con base en normas tales como API, ASTM, NOM, NMX, entre ot