/*!40000 ALTER TABLE `work_experience_activities` DISABLE KEYS */;
INSERT INTO `work_experience_activities` VALUES (1,1,'Coordinar las actividades con los Inspectores locales para atender las nominaciones para la inspección, y/o muestreo de diversos productos tales petroliferos y petroquimicos, carga general, tanto en Terminal, como Buque, en Contenedores; en ocasiones determinando cantidad mediante la técnica del Draft Surver. Asimismo, representar a la empresa localmente, así como administrar los recursos de la misma. Cuando es necesario realizar actividades de inspector con base a lo siguiente:',1),(2,1,'Atender nominaciones de servicio para la Inspección de producto (petroliferos y petroquimicos) tanto en tanques en tierra como en tanques a bordo de buques para realizar cálculos de cantidad conforme a normas técnicas del API Cap. 17.1 Directrices Marinas para Inspección de cargamentos.',2),(3,1,'Mediciones manuales en tanques de tierra conforme a la norma API 3.1A, y/o mediciones automaticas a bordo de buques conforme a las normas API 3.3. y API 3.5; Así como el cálculo de cantidades de producto con base a las normas API Cap. 12.1.1, y Cap 12.2.2, y considerando la densidad como lo establece el API Cap 9.1. Muestreo de diversos hidrocarburos (liquidos) en tanques de tierra, lineas de descarga, buques; basado en la norma API 8.1 (ASTM 4057). Inspección (medición y determinación de cantidades) y muestreo de hidrocarburos y LPG, tanto en el área local como en sitios foráneos asignados, conforme a las normas API 3.2; API Cap. 11.5.1, y Cap 11.5.2, 11.5.3; Cap. 9.2 ; y ASTM 1265.',3),(4,1,'Inspección On Hire Bunker Survey, Inspección Draft Survey, Supervisión de descarga / carga de Barco, Supervisión de descarga / carga de Contenedores, Supervisión de descarga / carga de camiones, Supervisión de descarga / carga de transportes FFCC, etc. particularmente en el manejo de productos de Carga general, minerales y agrícolas.Con base a normas GAFTA.',4),(5,1,'Conciliar cantidades con personal de la Terminal y/o Buque previo a la entrega de las cantidades oficiales de producto descargados, calculados a bordo del buque-tanque y lo recibido en tanques de tierra. Emisión de reportes de las inspecciones realizadas, basado en las normas técnicas aplicables y en las platillas electrónicas establecidas por la empresa.',5),(6,1,'Actividades de inspección, muestreo y/o testificación. Determinación de cantidades cargadas o descargadas de Barcos. Determinación de cantidades de Hidrocarburos cargadas o descargadas de Terminales a Buques y viceversa. Determinación de cantidades y/o calidad ( por cromatografía ) de LPG en Terminales y/o Buques. Inspección ce Cantidad y calidad en embarques de Acido Sulfúrico. Inspección, Inventario, Muestreo y Análisis en Almacenes de recepción de productos tales como maíz y trigo. Inspección, muestreo y análisis durante la recepción de embarques de productos agrícolas tales como Maíz, Sorgo y Trigo. Inspección de calidad y cantidad de Fertilizantes a granel de la industria agrícola.',6),(7,1,'Atender actividades establecidas en la descripción del puesto que ocupo en la organización; así como acvidades complementarias implícitas y explícitas a las operaciones que me asigne mi Jefe inmediato y/o la Gerencia General.',7),(8,2,'Inspeccion de Buques con productos derivados del petróleo (Petróleo). Crudo, LPG, Hidrocarburos, Productos Químicos y Aceites Lubricantes. Inspección de calidad y cantidad de embarques de Acido Sulfúrico.',1),(9,3,'Supervisor en el Departamento de Producción de Piña envasada en diferentes presentaciones.',1),(10,4,'Proporcionar servicios gerenciales de la empresa y a nuestros clientes y partes interesadas, desde el recibo y distribución de nominaciones de servicios de inspección, así mismo a fin de que estas se realicen de acuerdo a las políticas de la empresa, a través de la supervisión de los registros generados en campo, los cálculos, los muestreos, hasta la emisión de reportes a fin de proporcionar al cliente servicios completos e independientes con relación a cantidad y/o calidad de traslado, movimiento de producto. Supervisar, coordinar al personal y las operaciones (de área técnica correspondiente) que se realicen a nombre de la empresa.',1),(11,5,'Coordinación en el área de operaciones, así como calcular costos de cada uno de los servicios realizados para Caribbean, atención a clientes, realizar la logística de inspectores en campo, generar reportes estadísticos, apoyo en el área de facturación realizando preformas, generar informes en general para gerencia, supervisión de actividades de inspectores, revisión de cierre de gabinete de cada servicio, envió de reportes a clientes, realización de órdenes de compra para insumos de acuerdo al área.',1),(12,6,'Generar cotizaciones y ordenes de compra del área técnica Verificar el funcionamiento y operación de los equipos de todos los laboratorios - Proporcionar capacitación técnica a todo el personal - Aplicar programas de mantenimiento y calibración a cromatógrafos - Realizar programas y ejecutar supervisiones técnicas del personal',1),(13,7,'Ofrecer los servicios logísticos que ofrece la empresa a los importadores.',1),(14,8,'Realizar muestreos de hidrocarburos en barcos y tanques de tierra - Realizar análisis de laboratorio a hidrocarburos - Atestiguamiento de análisis y de muestreos',1),(15,9,'Atender los procesos de operación en el área de la planta de servicios auxiliares - Realizar y autorizar permisos de trabajo de la planta - Fungir como brigadista de emergencia durante mi turno',1),(16,10,'Inspección de carro tanques en tierra con carga de Gas LP, realizar cálculos de cantidad y pruebas de Densidad al producto. - Cálculo de cantidades de producto con base a las normas API Cap. 12.1.1, y Cap 12.2.2, y considerando la densidad como lo establece el API Cap 9.1.',1),(17,10,'- Inspección (medición y determinación de cantidades) y muestreo de hidrocarburos y LPG, tanto en el área local como en sitios foráneos asignados, conforme a las normas API 3.2; API Cap. 11.5.1, y Cap 11.5.2, 11.5.3 y ASTM 1265.',2),(18,10,'- Emisión de reportes de las inspecciones realizadas, basado en las normas técnicas aplicables y en las platillas electrónicas establecidas por la empresa.',3),(19,10,'- Atender actividades establecidas en la descripción del puesto que ocupo en la organización; así como acvidades complementarias implícitas y explícitas a las operaciones que me asigne mi Jefe inmediato y/o la Gerencia General.',4),(20,11,'Las Inspecciones para la consolidación, muestreos de Aceites, Inventarios de azúcar en sacos inventarios de granos y semillas en sacos y a granel determinación de daños y confrontas en contenedores y frigo contenedores. Inspección de cantidad y calidad de productos agrícolas tales como fríjol y Maíz.',1),(21,12,'Determinar la calidad de los productos terminados y/o la calidad de las materias primas, la calidad de las frutas, el azúcar en sacos y la recepción del jarabe que servía como endulzante para los jugos, la recepción de los camiones para la revisión de la calidad de los frutos, la inspección de la calidad del producto terminado (envasado). También en el área de producción y supervisión del personal en la planta.',1),(22,13,'Inspector Técnico para Caribbean Supervision LTD de México, empresa dedicada a los servicios de Inspección, pruebas y certificaciones de productos diversos tales como petróleo y sus derivados, agrícolas, y servicios técnicos Principales actividades; Realizar actividades y reporte de las mismas relacionadas con el proceso de inspección, • Inspección de carga / consolidación y /o daños de mercancía en contenedores • Inspección e Inventarios en plantas y almacenes de la Industria azucarera • Inspección, inventario, muestreo y análisis en almacenes de recepción, embarques de productos agrícolas • Inspección de cantidad / calidad de fertilizantes a granel para la industria agrícola • Así como también desarrollando otro tipo de inspecciones técnicas y la elaboración de reportes',1),(23,14,'Instalaci